export async function main(): Promise<{ message: string; count: number }> {
  return {
    message: "Hello from Script test",
    count: 5
  };
}

export async function main(): Promise<{ datetime: string; timestamp: number }> {
  const now = new Date();
  return {
    datetime: now.toISOString(),
    timestamp: now.getTime()
  };
}

export async function main(text: string): Promise<{ original: string; upper: string; length: number }> {
  return {
    original: text,
    upper: text.toUpperCase(),
    length: text.length
  };
}

export async function main(): Promise<{ uuid: string }> {
  return {
    uuid: crypto.randomUUID()
  };
}

export async function main(text: string, uuid: string, datetime: string): Promise<{ success: boolean; filepath: string; size: number; timestamp: string }> {
  const outputDir = '/tmp/habits-test';
  await Deno.mkdir(outputDir, { recursive: true });

  const filename = `test-${Date.now()}.txt`;
  const filepath = `${outputDir}/${filename}`;
  const content = `Text: ${text}\nUUID: ${uuid}\nDatetime: ${datetime}\n`;

  await Deno.writeTextFile(filepath, content);

  const stats = await Deno.stat(filepath);
  return {
    success: true,
    filepath,
    size: stats.size,
    timestamp: new Date().toISOString()
  };
}

export async function main(saveResult: any): Promise<{ verified: boolean; filepath: string; content: string; fileAgeMs: number; isRecent: boolean }> {
  const filepath = saveResult.filepath;

  try {
    const content = await Deno.readTextFile(filepath);
    const stats = await Deno.stat(filepath);
    const now = Date.now();
    const fileAge = now - (stats.mtime?.getTime() || 0);

    return {
      verified: true,
      filepath,
      content,
      fileAgeMs: fileAge,
      isRecent: fileAge < 60000
    };
  } catch (e) {
    return {
      verified: false,
      filepath,
      content: '',
      fileAgeMs: -1,
      isRecent: false
    };
  }
}
